import{_ as d,C as B,o as A,c as n,a5 as E,b as a,w as o,a as r,E as l,a4 as s}from"./chunks/framework.gGRxziV4.js";const S=JSON.parse('{"title":"02-Hooks 系统：给 AI 助手装上\\"触觉\\"和\\"自律\\"","description":"","frontmatter":{},"headers":[],"relativePath":"08-ECC教程/02-Hooks系统.md","filePath":"08-ECC教程/02-Hooks系统.md","lastUpdated":null}'),i={name:"08-ECC教程/02-Hooks系统.md"};function C(f,t,u,h,p,c){const e=B("Mermaid");return A(),n("div",null,[t[2]||(t[2]=E('<h1 id="_02-hooks-系统-给-ai-助手装上-触觉-和-自律" tabindex="-1">02-Hooks 系统：给 AI 助手装上&quot;触觉&quot;和&quot;自律&quot; <a class="header-anchor" href="#_02-hooks-系统-给-ai-助手装上-触觉-和-自律" aria-label="Permalink to &quot;02-Hooks 系统：给 AI 助手装上&quot;触觉&quot;和&quot;自律&quot;&quot;">​</a></h1><hr><h2 id="没有-hooks-的-claude-code-像什么" tabindex="-1">没有 Hooks 的 Claude Code 像什么？ <a class="header-anchor" href="#没有-hooks-的-claude-code-像什么" aria-label="Permalink to &quot;没有 Hooks 的 Claude Code 像什么？&quot;">​</a></h2><p>想象你雇了一个超级聪明的员工。TA 的技术能力一流，但有一个致命问题：<strong>TA 完全没有自我意识。</strong></p><ul><li>TA 改了一个文件，不知道应该去格式化一下</li><li>TA 写完一段代码，不知道应该跑一下测试</li><li>TA 忙了一下午，不知道应该把成果存个档</li><li>TA 要做一件危险的事，不知道应该先问你一声</li></ul><p>这不是 TA 不聪明，是 TA 没有&quot;触觉&quot;。TA 不知道自己刚做了一件事，更不知道做完之后应该做什么。</p><p>你可以每次手动提醒 TA——&quot;改完文件记得格式化&quot;、&quot;写完代码跑一下测试&quot;、&quot;别忘了存档&quot;。但你会累死，而且 TA 会忘。</p><p><strong>Hooks 就是给 TA 装上&quot;触觉&quot;和&quot;自律&quot;。</strong> 在特定时刻自动触发特定动作，不需要你手动干预。就像人的神经系统——碰到烫的东西，手会自动缩回来，不需要大脑专门思考&quot;我要缩手了&quot;。</p><hr><h2 id="为什么是这个生命周期-从人是怎么做事的来理解" tabindex="-1">为什么是这个生命周期？从人是怎么做事的来理解 <a class="header-anchor" href="#为什么是这个生命周期-从人是怎么做事的来理解" aria-label="Permalink to &quot;为什么是这个生命周期？从人是怎么做事的来理解&quot;">​</a></h2><p>ECC 定义了 6 个 Hook 点，覆盖了一个工作周期的每一个关键时刻。这不是随意设计的，而是从&quot;人是怎么做事的&quot;来理解的：</p>',11)),(A(),a(s,null,{default:o(()=>[l(e,{id:"mermaid-48",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20START(%5B%22%F0%9F%96%A5%EF%B8%8F%20%E6%89%93%E5%BC%80%E7%BB%88%E7%AB%AF%EF%BC%8C%E5%90%AF%E5%8A%A8%20Claude%20Code%22%5D)%0A%20%20%20%20START%20--%3E%20SS%5B%22%F0%9F%AA%9D%20SessionStart%5Cn%E5%B0%B1%E5%83%8F%E4%BA%BA%E6%97%A9%E4%B8%8A%E5%88%B0%E5%8A%9E%E5%85%AC%E5%AE%A4%5Cn%E6%89%93%E5%BC%80%E7%94%B5%E8%84%91%E3%80%81%E7%9C%8B%E6%98%A8%E5%A4%A9%E7%9A%84%E5%B7%A5%E4%BD%9C%E7%AC%94%E8%AE%B0%22%5D%0A%0A%20%20%20%20SS%20--%3E%20WORK%5B%22%E5%BC%80%E5%A7%8B%E5%B7%A5%E4%BD%9C...%22%5D%0A%0A%20%20%20%20WORK%20--%3E%20PRE%5B%22%F0%9F%AA%9D%20PreToolUse%5Cn%E5%B0%B1%E5%83%8F%E4%BA%BA%E5%81%9A%E4%BA%8B%E6%83%85%E5%89%8D%E6%83%B3%E4%B8%80%E6%83%B3%5Cn'%E8%BF%99%E4%B8%AA%E6%93%8D%E4%BD%9C%E5%AE%89%E5%85%A8%E5%90%97%EF%BC%9F'%22%5D%0A%0A%20%20%20%20PRE%20--%3E%20CHECK%7B%7B%22%E5%AE%89%E5%85%A8%E5%90%97%EF%BC%9F%22%7D%7D%0A%20%20%20%20CHECK%20--%3E%7C%22%E5%AE%89%E5%85%A8%22%7C%20TOOL%5B%22%E6%89%A7%E8%A1%8C%E5%B7%A5%E5%85%B7%E6%93%8D%E4%BD%9C%22%5D%0A%20%20%20%20CHECK%20--%3E%7C%22%E4%B8%8D%E5%AE%89%E5%85%A8%22%7C%20BLOCK%5B%22%F0%9F%9A%AB%20%E9%98%BB%E6%AD%A2%22%5D%0A%0A%20%20%20%20TOOL%20--%3E%20POST%5B%22%F0%9F%AA%9D%20PostToolUse%5Cn%E5%B0%B1%E5%83%8F%E4%BA%BA%E5%81%9A%E5%AE%8C%E4%BA%8B%E6%A3%80%E6%9F%A5%E4%B8%80%E4%B8%8B%5Cn'%E6%96%87%E4%BB%B6%E6%A0%BC%E5%BC%8F%E5%8C%96%E4%BA%86%E6%B2%A1%EF%BC%9F%E7%B1%BB%E5%9E%8B%E5%AF%B9%E4%B8%8D%E5%AF%B9%EF%BC%9F'%22%5D%0A%0A%20%20%20%20POST%20--%3E%20MORE%7B%7B%22%E8%BF%98%E6%9C%89%E5%B7%A5%E4%BD%9C%EF%BC%9F%22%7D%7D%0A%20%20%20%20MORE%20--%3E%7C%22%E6%98%AF%22%7C%20PRE%0A%20%20%20%20MORE%20--%3E%7C%22%E5%90%A6%22%7C%20STOP%5B%22%F0%9F%AA%9D%20Stop%5Cn%E5%B0%B1%E5%83%8F%E4%BA%BA%E4%B8%8B%E7%8F%AD%E5%89%8D%E6%95%B4%E7%90%86%E6%A1%8C%E9%9D%A2%5Cn'%E4%BB%8A%E5%A4%A9%E5%81%9A%E4%BA%86%E4%BB%80%E4%B9%88%EF%BC%9F%E5%AD%98%E4%B8%AA%E6%A1%A3'%22%5D%0A%0A%20%20%20%20STOP%20--%3E%20SE%5B%22%F0%9F%AA%9D%20SessionEnd%5Cn%E5%B0%B1%E5%83%8F%E4%BA%BA%E5%85%B3%E7%94%B5%E8%84%91%E8%B5%B0%E4%BA%BA%5Cn'%E4%BB%8A%E5%A4%A9%E5%88%B0%E6%AD%A4%E4%B8%BA%E6%AD%A2'%22%5D%0A%0A%20%20%20%20SE%20--%3E%20PC%5B%22%F0%9F%AA%9D%20PreCompact%5Cn%E5%B0%B1%E5%83%8F%E4%BA%BA%E5%AE%9A%E6%9C%9F%E6%95%B4%E7%90%86%E6%88%BF%E9%97%B4%5Cn'%E4%B8%8A%E4%B8%8B%E6%96%87%E5%BF%AB%E6%BB%A1%E4%BA%86%EF%BC%8C%E5%BD%92%E6%A1%A3%E4%B8%80%E4%B8%8B'%22%5D%0A%0A%20%20%20%20style%20START%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A%20%20%20%20style%20SS%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A%20%20%20%20style%20WORK%20fill%3A%2378909c%2Ccolor%3A%23fff%0A%20%20%20%20style%20PRE%20fill%3A%23ffa726%2Ccolor%3A%23fff%0A%20%20%20%20style%20CHECK%20fill%3A%23ef5350%2Ccolor%3A%23fff%0A%20%20%20%20style%20TOOL%20fill%3A%2390a4ae%2Ccolor%3A%23fff%0A%20%20%20%20style%20BLOCK%20fill%3A%23d32f2f%2Ccolor%3A%23fff%0A%20%20%20%20style%20POST%20fill%3A%23ffa726%2Ccolor%3A%23fff%0A%20%20%20%20style%20MORE%20fill%3A%2378909c%2Ccolor%3A%23fff%0A%20%20%20%20style%20STOP%20fill%3A%23ab47bc%2Ccolor%3A%23fff%0A%20%20%20%20style%20SE%20fill%3A%23ab47bc%2Ccolor%3A%23fff%0A%20%20%20%20style%20PC%20fill%3A%23ab47bc%2Ccolor%3A%23fff%0A"})]),fallback:o(()=>[...t[0]||(t[0]=[r(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=E('<p>让我用人话解释每个 Hook 为什么存在：</p><h3 id="sessionstart-——-早上到办公室" tabindex="-1">SessionStart —— 早上到办公室 <a class="header-anchor" href="#sessionstart-——-早上到办公室" aria-label="Permalink to &quot;SessionStart —— 早上到办公室&quot;">​</a></h3><p>你每天早上到办公室，第一件事是什么？打开电脑，看看昨天的工作笔记，回忆一下做到哪了。</p><p>SessionStart 做的就是这件事。Claude Code 启动时，ECC 自动加载上次会话保存的记忆——昨天讨论了什么、改了哪些文件、遇到了什么问题。TA 不用你从头介绍，TA 自己会&quot;想起来&quot;。</p><p><strong>这个 Hook 解决了&quot;不记事&quot;的痛点。</strong> 没有这个 Hook，你每次重启终端都要把背景重新说一遍。</p><h3 id="pretooluse-——-做事前想一想" tabindex="-1">PreToolUse —— 做事前想一想 <a class="header-anchor" href="#pretooluse-——-做事前想一想" aria-label="Permalink to &quot;PreToolUse —— 做事前想一想&quot;">​</a></h3><p>你准备提交代码了，按 Git commit 之前，你会想一想：&quot;我改了什么？有没有漏掉什么？&quot;</p><p>PreToolUse 就是这个&quot;想一想&quot;的时刻。AI 准备使用一个工具（比如写文件、执行命令、提交代码）之前，ECC 会自动检查：</p><ul><li>这个操作安全吗？会不会把密钥提交到 GitHub？</li><li>这个操作合规吗？有没有违反团队的规矩？</li><li>这个操作合理吗？有没有更安全的替代方案？</li></ul><p><strong>这个 Hook 解决了&quot;安全&quot;的痛点。</strong> 它是安全检查的主要防线——在 AI 动手之前就拦住危险操作。</p><h3 id="posttooluse-——-做完事检查一下" tabindex="-1">PostToolUse —— 做完事检查一下 <a class="header-anchor" href="#posttooluse-——-做完事检查一下" aria-label="Permalink to &quot;PostToolUse —— 做完事检查一下&quot;">​</a></h3><p>你改完一个文件，保存后编辑器自动帮你格式化了。你甚至没注意到——因为这是自动的。</p><p>PostToolUse 做的就是这件事。AI 改完文件后，ECC 自动检测项目用了什么格式化工具（Biome？Prettier？），自动帮你跑一遍。还会检查类型（TypeScript 有没有报错？），检查有没有遗留 console.log。</p><p><strong>这个 Hook 解决了&quot;质量&quot;的痛点。</strong> AI 写出来的代码，自动经过质量门禁，你看到的永远是整洁的代码。</p><h3 id="stop-——-下班前整理桌面" tabindex="-1">Stop —— 下班前整理桌面 <a class="header-anchor" href="#stop-——-下班前整理桌面" aria-label="Permalink to &quot;Stop —— 下班前整理桌面&quot;">​</a></h3><p>你每天下班前会做什么？整理一下桌面，记个今天的 TODO，把重要的东西存档。</p><p>Stop 做的就是这件事。AI 完成一次回答后，ECC 自动保存会话状态、记录 token 使用和费用、在 macOS 上弹出桌面通知告诉你&quot;任务完成了&quot;。</p><p><strong>这个 Hook 解决了&quot;存档&quot;的痛点。</strong> 每次重要交互都会被记录，下次启动时 SessionStart 会加载这些记录。</p><h3 id="sessionend-——-关电脑走人" tabindex="-1">SessionEnd —— 关电脑走人 <a class="header-anchor" href="#sessionend-——-关电脑走人" aria-label="Permalink to &quot;SessionEnd —— 关电脑走人&quot;">​</a></h3><p>你关掉终端、结束一天的工作。SessionEnd 做最后的收尾：标记会话结束、保存最终状态。</p><p>这个 Hook 和 Stop 的区别是：Stop 是&quot;每次回答完&quot;触发，SessionEnd 是&quot;整个会话结束&quot;触发。就像你每次写完一个段落会存盘（Stop），但下班关电脑时会做一次完整的备份（SessionEnd）。</p><h3 id="precompact-——-定期整理房间" tabindex="-1">PreCompact —— 定期整理房间 <a class="header-anchor" href="#precompact-——-定期整理房间" aria-label="Permalink to &quot;PreCompact —— 定期整理房间&quot;">​</a></h3><p>Claude Code 的上下文窗口是有限的。聊得多了，前面的内容会被&quot;压缩&quot;掉。但在压缩之前，ECC 会在 PreCompact Hook 中把重要信息存档——这样即使上下文被压缩了，关键信息也不会丢失。</p><p><strong>这个 Hook 解决了&quot;遗忘&quot;的痛点。</strong> 上下文窗口再大也会满，但通过 PreCompact 存档，重要的记忆不会丢失。</p><hr><h2 id="为什么用-profile-三级体系" tabindex="-1">为什么用 Profile 三级体系？ <a class="header-anchor" href="#为什么用-profile-三级体系" aria-label="Permalink to &quot;为什么用 Profile 三级体系？&quot;">​</a></h2><p>ECC 的 Hooks 不是全开或全关的，它有一个&quot;安保级别&quot;系统，分为三级。为什么需要三级？因为不同场景需要不同级别的&quot;纪律&quot;：</p>',27)),(A(),a(s,null,{default:o(()=>[l(e,{id:"mermaid-142",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20subgraph%20MIN%5B%22%F0%9F%9F%A2%20minimal%20%E2%80%94%20%E7%8B%AC%E5%B1%85%E6%A8%A1%E5%BC%8F%22%5D%0A%20%20%20%20%20%20%20%20M1%5B%22SessionStart%20%2F%20SessionEnd%5Cn%E8%AE%B0%E4%BD%8F%E8%BF%9B%E5%87%BA%E5%B0%B1%E8%A1%8C%22%5D%0A%20%20%20%20%20%20%20%20M2%5B%22Stop%20%E5%AD%98%E6%A1%A3%5Cn%E4%B8%8B%E7%8F%AD%E5%AD%98%E4%B8%AA%E6%A1%A3%22%5D%0A%20%20%20%20%20%20%20%20M3%5B%22%E6%88%90%E6%9C%AC%E8%BF%BD%E8%B8%AA%5Cn%E8%8A%B1%E4%BA%86%E5%A4%9A%E5%B0%91%E9%92%B1%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20STD%5B%22%F0%9F%9F%A1%20standard%20%E2%80%94%20%E5%90%88%E7%A7%9F%E6%A8%A1%E5%BC%8F%EF%BC%88%E9%BB%98%E8%AE%A4%EF%BC%89%22%5D%0A%20%20%20%20%20%20%20%20S1%5B%22%E5%85%A8%E9%83%A8%20minimal%20%E5%8A%9F%E8%83%BD%22%5D%0A%20%20%20%20%20%20%20%20S2%5B%22%E8%B4%A8%E9%87%8F%E9%97%A8%E7%A6%81%5Cn%E6%94%B9%E5%AE%8C%E8%87%AA%E5%8A%A8%E6%A3%80%E6%9F%A5%22%5D%0A%20%20%20%20%20%20%20%20S3%5B%22%E6%A1%8C%E9%9D%A2%E9%80%9A%E7%9F%A5%5Cn%E6%9C%89%E4%BA%BA%E5%B8%AE%E4%BD%A0%E7%9C%8B%E7%9D%80%22%5D%0A%20%20%20%20%20%20%20%20S4%5B%22%E6%8C%81%E7%BB%AD%E5%AD%A6%E4%B9%A0%5Cn%E8%B6%8A%E7%94%A8%E8%B6%8A%E5%A5%BD%22%5D%0A%20%20%20%20%20%20%20%20S5%5B%22console.log%20%E8%AD%A6%E5%91%8A%5Cn%E5%88%AB%E7%95%99%E4%B8%8B%E8%B0%83%E8%AF%95%E4%BB%A3%E7%A0%81%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20STR%5B%22%F0%9F%94%B4%20strict%20%E2%80%94%20%E5%85%AC%E5%8F%B8%E6%A8%A1%E5%BC%8F%22%5D%0A%20%20%20%20%20%20%20%20ST1%5B%22%E5%85%A8%E9%83%A8%20standard%20%E5%8A%9F%E8%83%BD%22%5D%0A%20%20%20%20%20%20%20%20ST2%5B%22%E8%87%AA%E5%8A%A8%E6%A0%BC%E5%BC%8F%E5%8C%96%5Cn%E4%BB%A3%E7%A0%81%E6%B0%B8%E8%BF%9C%E6%95%B4%E6%B4%81%22%5D%0A%20%20%20%20%20%20%20%20ST3%5B%22%E7%B1%BB%E5%9E%8B%E6%A3%80%E6%9F%A5%5CnTypeScript%20%E9%9B%B6%E6%8A%A5%E9%94%99%22%5D%0A%20%20%20%20%20%20%20%20ST4%5B%22%E9%85%8D%E7%BD%AE%E6%96%87%E4%BB%B6%E4%BF%9D%E6%8A%A4%5Cn%E5%88%AB%E5%8A%A8%E8%A7%84%E5%88%99%E9%85%8D%E7%BD%AE%22%5D%0A%20%20%20%20%20%20%20%20ST5%5B%22%E5%AE%89%E5%85%A8%E6%89%AB%E6%8F%8F%5Cn%E5%AF%86%E9%92%A5%E6%A3%80%E6%B5%8B%20%2B%20%E6%B3%A8%E5%85%A5%E6%A3%80%E6%B5%8B%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20MIN%20--%3E%7C%22%E5%8D%87%E7%BA%A7%22%7C%20STD%20--%3E%7C%22%E5%8D%87%E7%BA%A7%22%7C%20STR%0A%0A%20%20%20%20style%20MIN%20fill%3A%23e8f5e9%2Cstroke%3A%234caf50%0A%20%20%20%20style%20STD%20fill%3A%23fff8e1%2Cstroke%3A%23ff9800%0A%20%20%20%20style%20STR%20fill%3A%23fce4ec%2Cstroke%3A%23f44336%0A%20%20%20%20style%20M1%20fill%3A%2381c784%2Ccolor%3A%23fff%0A%20%20%20%20style%20M2%20fill%3A%2381c784%2Ccolor%3A%23fff%0A%20%20%20%20style%20M3%20fill%3A%2381c784%2Ccolor%3A%23fff%0A%20%20%20%20style%20S1%20fill%3A%23ffb74d%2Ccolor%3A%23fff%0A%20%20%20%20style%20S2%20fill%3A%23ffb74d%2Ccolor%3A%23fff%0A%20%20%20%20style%20S3%20fill%3A%23ffb74d%2Ccolor%3A%23fff%0A%20%20%20%20style%20S4%20fill%3A%23ffb74d%2Ccolor%3A%23fff%0A%20%20%20%20style%20S5%20fill%3A%23ffb74d%2Ccolor%3A%23fff%0A%20%20%20%20style%20ST1%20fill%3A%23e57373%2Ccolor%3A%23fff%0A%20%20%20%20style%20ST2%20fill%3A%23e57373%2Ccolor%3A%23fff%0A%20%20%20%20style%20ST3%20fill%3A%23e57373%2Ccolor%3A%23fff%0A%20%20%20%20style%20ST4%20fill%3A%23e57373%2Ccolor%3A%23fff%0A%20%20%20%20style%20ST5%20fill%3A%23e57373%2Ccolor%3A%23fff%0A"})]),fallback:o(()=>[...t[1]||(t[1]=[r(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=E('<p><strong>minimal —— 独居模式。</strong> 你一个人在家，基本卫生就行。只有记忆存档和成本追踪，没有太多约束。适合快速原型、个人小项目、&quot;先跑起来再说&quot;的场景。</p><p><strong>standard —— 合租模式（默认）。</strong> 你跟人合住，公共区域要维护好。有质量门禁、桌面通知、持续学习。适合大多数项目——既不会太自由（质量失控），也不会太严格（影响效率）。</p><p><strong>strict —— 公司模式。</strong> 你在公司上班，每一步都有规范。自动格式化、类型检查、配置文件保护、安全扫描全部开启。适合团队项目、生产代码、安全敏感的项目。每一步都有人看着，质量有保障。</p><p><strong>默认就是 standard</strong>——对大多数人来说刚刚好。你可以根据项目需要随时切换。</p><hr><h2 id="为什么-session-记忆这么重要" tabindex="-1">为什么 Session 记忆这么重要？ <a class="header-anchor" href="#为什么-session-记忆这么重要" aria-label="Permalink to &quot;为什么 Session 记忆这么重要？&quot;">​</a></h2><p>这个值得单独说一下，因为它是很多人觉得&quot;AI 编程助手不好用&quot;的根本原因。</p><p><strong>没有记忆的工作体验：</strong></p><blockquote><p>你：昨天我们讨论了 OAuth 怎么配，你还记得吗？ AI：不好意思，我不记得了。你能再说一遍吗？ 你：（把昨天说的话重复一遍） AI：好的，我理解了。那我们开始吧。 你：等等，上次你试过方案 A，不行，要换方案 B。 AI：方案 A 为什么不行？ 你：（解释了一遍原因） AI：好的，那我们用方案 B。 你：（崩溃）</p></blockquote><p><strong>有记忆的工作体验：</strong></p><blockquote><p>你：继续昨天的 OAuth 工作。 AI：好的，我记得昨天试了方案 A，因为 XX 原因不行，我们决定用方案 B。上次做到配好了 callback URL，接下来应该处理 token 刷新。需要我继续吗？ 你：对，继续吧。 AI：好的，我先检查一下昨天的代码... 你：（微笑）</p></blockquote><p>差距不是一点半点。有记忆的 AI 不只是&quot;记得你说了什么&quot;，而是能理解<strong>上下文</strong>——知道为什么做了某个决策、遇到了什么问题、下一步该做什么。这就像跟一个靠谱的同事合作 vs 跟一个每次重新认识的新人合作。</p><hr><h2 id="实际配置的-hooks-一览表" tabindex="-1">实际配置的 Hooks：一览表 <a class="header-anchor" href="#实际配置的-hooks-一览表" aria-label="Permalink to &quot;实际配置的 Hooks：一览表&quot;">​</a></h2><p>ECC 安装后实际配置了哪些 Hook？看这张表就够了：</p><h3 id="sessionstart" tabindex="-1">SessionStart <a class="header-anchor" href="#sessionstart" aria-label="Permalink to &quot;SessionStart&quot;">​</a></h3><table tabindex="0"><thead><tr><th>作用</th><th>说明</th></tr></thead><tbody><tr><td>加载上次记忆</td><td>自动读取之前会话保存的状态</td></tr><tr><td>检测包管理器</td><td>自动识别项目用 npm/yarn/pnpm/bun</td></tr></tbody></table><h3 id="pretooluse" tabindex="-1">PreToolUse <a class="header-anchor" href="#pretooluse" aria-label="Permalink to &quot;PreToolUse&quot;">​</a></h3><table tabindex="0"><thead><tr><th>作用</th><th>说明</th></tr></thead><tbody><tr><td>阻止跳过 Git Hook</td><td>不允许 <code>git commit --no-verify</code> 绕过检查</td></tr><tr><td>tmux 长命令提醒</td><td>用 tmux 运行长耗时命令，避免终端卡住</td></tr><tr><td>git push 提醒</td><td>push 前提醒检查变更</td></tr><tr><td>文档文件警告</td><td>写非标准文档文件时提醒</td></tr><tr><td>持续学习观察</td><td>捕获操作数据用于学习</td></tr><tr><td>MCP 健康检查</td><td>MCP 服务不可用时阻止调用</td></tr><tr><td>配置文件保护</td><td>阻止修改 linter/formatter 配置</td></tr></tbody></table><h3 id="posttooluse" tabindex="-1">PostToolUse <a class="header-anchor" href="#posttooluse" aria-label="Permalink to &quot;PostToolUse&quot;">​</a></h3><table tabindex="0"><thead><tr><th>作用</th><th>说明</th></tr></thead><tbody><tr><td>PR 创建记录</td><td>创建 PR 后自动记录 URL 并提示审查</td></tr><tr><td>质量门禁</td><td>文件编辑后自动检查质量</td></tr><tr><td>自动格式化</td><td>编辑 JS/TS 文件后自动格式化（strict 级别）</td></tr><tr><td>类型检查</td><td>编辑 TS 文件后自动运行 tsc（strict 级别）</td></tr><tr><td>console.log 警告</td><td>编辑后检查是否有遗留的调试代码</td></tr><tr><td>持续学习观察</td><td>捕获结果数据用于学习</td></tr></tbody></table><h3 id="stop" tabindex="-1">Stop <a class="header-anchor" href="#stop" aria-label="Permalink to &quot;Stop&quot;">​</a></h3><table tabindex="0"><thead><tr><th>作用</th><th>说明</th></tr></thead><tbody><tr><td>console.log 最终检查</td><td>每次回答后检查修改文件中是否有遗留调试代码</td></tr><tr><td>状态持久化</td><td>保存会话状态</td></tr><tr><td>会话评估</td><td>分析会话中可学习的模式</td></tr><tr><td>成本追踪</td><td>记录 token 使用和费用</td></tr><tr><td>桌面通知</td><td>macOS 系统通知你任务完成</td></tr></tbody></table><h3 id="sessionend-precompact" tabindex="-1">SessionEnd / PreCompact <a class="header-anchor" href="#sessionend-precompact" aria-label="Permalink to &quot;SessionEnd / PreCompact&quot;">​</a></h3><table tabindex="0"><thead><tr><th>作用</th><th>说明</th></tr></thead><tbody><tr><td>会话结束标记</td><td>标记会话生命周期结束</td></tr><tr><td>上下文压缩前存档</td><td>压缩前保存重要信息</td></tr></tbody></table><hr><h2 id="你不需要改任何东西" tabindex="-1">你不需要改任何东西 <a class="header-anchor" href="#你不需要改任何东西" aria-label="Permalink to &quot;你不需要改任何东西&quot;">​</a></h2><p>看到这里你可能觉得：&quot;哇，这么多 Hook，我要一个个配置吗？&quot;</p><p><strong>不需要。</strong></p><p>ECC 安装后，默认就开启了 standard 级别的所有 Hooks。你直接用就行。</p><ul><li>想少一点干扰？切到 <code>minimal</code></li><li>想更严格？切到 <code>strict</code></li><li>想自定义某个 Hook？参考 <code>hooks.json</code> 的配置修改</li></ul><p><strong>大多数情况下，默认配置就是最佳选择。</strong> ECC 的作者用了 10 个月才调出来的默认值，比你瞎调靠谱。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>现在你知道 ECC 的&quot;自动触发器&quot;是怎么工作的了。接下来读 <a href="./03-Agent系统.html">03-Agent系统</a>，了解那 28 个&quot;AI 专家&quot;是怎么帮你干活的——他们分工协作，让对的人干对的事。</p>',35))])}const b=d(i,[["render",C]]);export{S as __pageData,b as default};
